import { CurrencyPipe } from '@angular/common';
import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { Artwork } from '../../interfaces/artwork.interface';
import { ArtworkAuctionSummary } from '../../interfaces/auction.interface';
import { SiteLanguage } from '../../interfaces/language.interface';

@Component({
  selector: 'app-artwork-info',
  standalone: true,
  imports: [CurrencyPipe, RouterLink],
  templateUrl: './artwork-info.component.html',
  styleUrl: './artwork-info.component.sass'
})
export class ArtworkInfoComponent {
  @Input({ required: true }) artwork!: Artwork;
  @Input({ required: true }) language!: SiteLanguage;
  @Input({ required: true }) artistEmail!: string;
  @Input() layout: 'default' | 'product' = 'default';
  @Input() auctionPath: string | null = null;
  @Input() auctionSummary: ArtworkAuctionSummary | null = null;

  protected get statusLabel(): string {
    const labels = {
      it: {
        available: 'Disponibile',
        sold: 'Venduta',
        reserved: 'Riservata',
        private_collection: 'Collezione privata',
        not_available: 'Non disponibile'
      },
      en: {
        available: 'Available',
        sold: 'Sold',
        reserved: 'Reserved',
        private_collection: 'Private Collection',
        not_available: 'Not Available'
      }
    };

    return labels[this.language][this.artwork.status];
  }

  protected get shouldShowDescription(): boolean {
    return this.artwork.texts.visibleMode === 'description' || this.artwork.texts.visibleMode === 'both';
  }

  protected get shouldShowPoetic(): boolean {
    return this.artwork.texts.visibleMode === 'poetic' || this.artwork.texts.visibleMode === 'both';
  }

  protected get shouldShowPrice(): boolean {
    return this.artwork.price.amount !== null;
  }

  protected get techniqueSupportLabel(): string {
    const technique = this.artwork.technique[this.language] || this.artwork.technique.it;
    const support = this.normalizeSupportLabel(this.artwork.support[this.language] || this.artwork.support.it);
    return support ? `${technique} ${this.language === 'it' ? 'su' : 'on'} ${support}` : technique;
  }

  protected get hasAuctionPriority(): boolean {
    return this.auctionSummary?.publicStatus === 'live' || this.auctionSummary?.publicStatus === 'upcoming';
  }

  protected get isUnavailable(): boolean {
    return this.artwork.status === 'sold' || this.artwork.status === 'private_collection' || this.artwork.status === 'not_available';
  }

  protected get auctionLabel(): string {
    if (!this.auctionSummary) {
      return '';
    }

    if (this.auctionSummary.publicStatus === 'live') {
      return this.language === 'it' ? 'Asta in corso' : 'Auction live';
    }

    if (this.auctionSummary.publicStatus === 'upcoming') {
      return this.language === 'it' ? 'Asta in apertura' : 'Auction opening soon';
    }

    return this.language === 'it' ? 'Asta conclusa' : 'Auction closed';
  }

  protected get primaryCtaLabel(): string {
    if (this.hasAuctionPriority) {
      return this.language === 'it' ? 'Vai all asta' : 'Go to auction';
    }

    return this.isUnavailable
      ? (this.language === 'it' ? 'Richiedi dettagli' : 'Request details')
      : (this.language === 'it' ? 'Richiedi informazioni' : 'Request information');
  }

  protected get secondaryCtaLabel(): string {
    return this.isUnavailable
      ? (this.language === 'it' ? 'Contatta l artista' : 'Contact the artist')
      : (this.language === 'it' ? 'Richiedi informazioni' : 'Request information');
  }

  protected get auctionMessage(): string {
    if (!this.auctionSummary) {
      return '';
    }

    if (this.auctionSummary.publicStatus === 'live') {
      return this.language === 'it'
        ? 'Quest opera e attualmente in asta. Per seguire rilanci e stato pubblico usa la pagina dedicata.'
        : 'This artwork is currently at auction. Use the dedicated page to follow bids and the public status.';
    }

    if (this.auctionSummary.publicStatus === 'upcoming') {
      return this.language === 'it'
        ? 'Quest opera andra in asta a breve. La pagina dedicata raccoglie tempi e dettagli pubblici.'
        : 'This artwork will go to auction soon. The dedicated page collects timing and public details.';
    }

    return this.language === 'it'
      ? 'Per questa opera e disponibile anche la scheda dell asta conclusa.'
      : 'A public page is also available for this closed auction.';
  }

  protected get mailtoLink(): string {
    const title = this.language === 'it' ? this.artwork.title.it : this.artwork.title.en || this.artwork.title.it;
    const subject = this.language === 'it'
      ? `Richiesta informazioni: ${title}`
      : `Request information: ${title}`;

    return `mailto:${this.artistEmail}?subject=${encodeURIComponent(subject)}`;
  }

  private normalizeSupportLabel(rawSupport: string): string {
    const support = String(rawSupport || '').trim();
    if (!support) {
      return '';
    }

    const lowered = support.toLowerCase();
    const supportMap: Array<{ pattern: RegExp; it: string; en: string }> = [
      { pattern: /\btela\b|\bcanvas\b/, it: 'tela', en: 'canvas' },
      { pattern: /\bcarta\b|\bpaper\b/, it: 'carta', en: 'paper' },
      { pattern: /\btavola\b|\bpanel\b/, it: 'tavola', en: 'panel' },
      { pattern: /\blegno\b|\bwood\b/, it: 'legno', en: 'wood' },
      { pattern: /\bpuzzle\b/, it: 'puzzle', en: 'puzzle' },
      { pattern: /\bcartone\b|\bcardboard\b/, it: 'cartone', en: 'cardboard' },
      { pattern: /\brame\b|\bcopper\b/, it: 'rame', en: 'copper' },
      { pattern: /\balluminio\b|\baluminum\b|\baluminium\b/, it: 'alluminio', en: 'aluminium' }
    ];

    const matched = supportMap.find((entry) => entry.pattern.test(lowered));
    if (matched) {
      return this.language === 'it' ? matched.it : matched.en;
    }

    if (lowered.length > 40 || lowered.includes('dipinto') || lowered.includes('opera')) {
      return this.language === 'it' ? 'tela' : 'canvas';
    }

    return support;
  }
}
